// REQUIRES: riscv-registered-target

#include <riscv_vector.h>

// CHECK-LABEL: @shl_i32(
// CHECK-NEXT:  entry:
// CHECK-NEXT:    [[SHL:%.*]] = shl <vscale x 2 x i32> [[A:%.*]], [[B:%.*]]
// CHECK-NEXT:    ret <vscale x 2 x i32> [[SHL]]
//
vint32m1_t shl_i32(vint32m1_t a, vint32m1_t b) {
  return a << b;
}

// CHECK-LABEL: @ashr_i32(
// CHECK-NEXT:  entry:
// CHECK-NEXT:    [[SHR:%.*]] = ashr <vscale x 2 x i32> [[A:%.*]], [[B:%.*]]
// CHECK-NEXT:    ret <vscale x 2 x i32> [[SHR]]
//
vint32m1_t ashr_i32(vint32m1_t a, vint32m1_t b) {
  return a >> b;
}

// CHECK-LABEL: @lshr_u32(
// CHECK-NEXT:  entry:
// CHECK-NEXT:    [[SHR:%.*]] = lshr <vscale x 2 x i32> [[A:%.*]], [[B:%.*]]
// CHECK-NEXT:    ret <vscale x 2 x i32> [[SHR]]
//
vuint32m1_t lshr_u32(vuint32m1_t a, vuint32m1_t b) {
  return a >> b;
}

// CHECK-LABEL: @compound_lshr_u32(
// CHECK-NEXT:  entry:
// CHECK-NEXT:    [[SHR:%.*]] = lshr <vscale x 2 x i32> [[A:%.*]], [[B:%.*]]
// CHECK-NEXT:    ret <vscale x 2 x i32> [[SHR]]
//
vuint32m1_t compound_lshr_u32(vuint32m1_t a, vuint32m1_t b) {
  a >>= b;
  return a;
}
